#include <bits/stdc++.h>
using namespace std;

int main(){
	int n;
	cin>>n;
	int a[n],b[n];
	for(int i=0;i<n;i++){
		cin>>a[i];
	}
	for(int i=0;i<n-1;i++){
		b[i]=abs(a[i]-a[i+1]);
	}

	for(int i=1;i<=n-1;i++){
		bool has = false;
		for(int j=0;j<=n-1;j++){
			if(i==b[j]){
				has = true;
			}
		}
		if(!has){
			cout<<"Not jolly";
			return 0;
		}
	}
	cout<<"Jolly";
	return 0;
}
